1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using Microsoft.Extensions.ML;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. // --- Train the model at startup and save to disk ---
8. var mlContext = new MLContext(seed: 42);
9. var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
10. var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Model", "churn-model.zip");
11. 
12. IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
13.     dataPath, hasHeader: true, separatorChar: ',');
14. 
15. // Map "Yes"/"No" string to boolean Label column
16. var labelLookup = new[] { new LabelMapping { ChurnedText = "Yes", Label = true },
17.                           new LabelMapping { ChurnedText = "No",  Label = false } };
18. var lookupData = mlContext.Data.LoadFromEnumerable(labelLookup);
19. 
20. var pipeline = mlContext.Transforms.Conversion.MapValue(
21.         "Label", lookupData,
22.         lookupData.Schema["ChurnedText"], lookupData.Schema["Label"],
23.         inputColumnName: nameof(CustomerData.ChurnedText))
24.     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
25.     .Append(mlContext.Transforms.Concatenate("Features",
26.         nameof(CustomerData.Age),
27.         nameof(CustomerData.Income),
28.         "RegionEncoded",
29.         nameof(CustomerData.PurchaseHistory)))
30.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
31.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
32.         labelColumnName: "Label",
33.         featureColumnName: "Features"));
34. 
35. // Train final model on all data
36. var model = pipeline.Fit(dataView);
37. 
38. // Evaluate on training data (best we can do with very small datasets)
39. try
40. {
41.     var predictions = model.Transform(dataView);
42.     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
43.     Console.WriteLine("=== Churn Model Metrics ===");
44.     Console.WriteLine($"  Accuracy:  {metrics.Accuracy:F4}");
45.     Console.WriteLine($"  AUC:       {metrics.AreaUnderRocCurve:F4}");
46.     Console.WriteLine($"  F1 Score:  {metrics.F1Score:F4}");
47.     Console.WriteLine("  Note: Metrics on training data (dataset too small for hold-out split).");
48.     Console.WriteLine("  Add more rows and use TrainTestSplit for reliable evaluation.");
49. }
50. catch (Exception ex)
51. {
52.     Console.WriteLine($"  Evaluation skipped: {ex.Message}");
53. }
54. 
55. Directory.CreateDirectory(Path.GetDirectoryName(modelPath)!);
56. mlContext.Model.Save(model, dataView.Schema, modelPath);
57. Console.WriteLine($"Model saved to {modelPath}");
58. 
59. // --- Register prediction engine pool (thread-safe) ---
60. builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
61.     .FromFile(modelPath);
62. 
63. var app = builder.Build();
64. 
65. app.MapGet("/", () => "Churn Predictor API — POST to /predict");
66. 
67. app.MapPost("/predict", (
68.     PredictionEnginePool<CustomerData, ChurnPrediction> pool,
69.     CustomerRequest req) =>
70. {
71.     var input = new CustomerData
72.     {
73.         Age = req.Age,
74.         Income = req.Income,
75.         Region = req.Region,
76.         PurchaseHistory = req.PurchaseHistory
77.     };
78.     var result = pool.Predict(input);
79.     return Results.Ok(new
80.     {
81.         WillChurn = result.PredictedLabel,
82.         Confidence = result.Probability
83.     });
84. });
85. 
86. app.Run();
87. 
