 var builder = WebApplication.CreateBuilder(args);

 // --- Train the model at startup and save to disk ---
 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Model", "churn-model.zip");

 IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
     dataPath, hasHeader: true, separatorChar: ',');

 // Map "Yes"/"No" string to boolean Label column
 var labelLookup = new[] { new LabelMapping { ChurnedText = "Yes", Label = true },
                           new LabelMapping { ChurnedText = "No",  Label = false } };
 var lookupData = mlContext.Data.LoadFromEnumerable(labelLookup);

 var pipeline = mlContext.Transforms.Conversion.MapValue(
         "Label", lookupData,
         lookupData.Schema["ChurnedText"], lookupData.Schema["Label"],
         inputColumnName: nameof(CustomerData.ChurnedText))
     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(CustomerData.Age),
         nameof(CustomerData.Income),
         "RegionEncoded",
         nameof(CustomerData.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
